/* CompTIA AI Fundamentals :: content/quiz3.js — question bank for Domain 3 (100 items). */
window.AIFUND = window.AIFUND || {}; AIFUND.questions = AIFUND.questions || [];
AIFUND.questions.push(
{ id:"D3-001", domain:3, obj:"3.1", diff:"easy", q:"What is a \"prompt\" when working with a tool like ChatGPT, Gemini, or Claude?", options:["The instruction or question you type to tell the AI what you want","The internet connection the tool uses to run","The subscription plan you pay for each month","The company that built the AI model"], answer:0, explain:"<strong>The instruction or question you type</strong> is the prompt; it is how you communicate to the model what task you want done and in what form.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The internet connection the tool uses to run</b>: connectivity lets the app reach the model but is not the message you send it.</span><span class='qd'><b>The subscription plan you pay for each month</b>: your plan affects access and limits, not the meaning of the word prompt.</span><span class='qd'><b>The company that built the AI model</b>: the vendor makes the model; it is not the text you enter.</span>" },
{ id:"D3-002", domain:3, obj:"3.1", diff:"medium", q:"Which prompt is most likely to get a useful, on-target answer?", options:["\"Write something about my apartment.\"","\"Write a 150-word friendly email to my landlord requesting a repair for a leaking kitchen faucet, and ask for a visit this week.\"","\"Email.\"","\"Help me.\""], answer:1, explain:"<strong>The detailed request</strong> specifies audience, length, tone, topic, and the desired action, giving the model everything it needs to produce a targeted result.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>\"Write something about my apartment.\"</b>: this is vague about purpose, audience, and format, so the output is a guess.</span><span class='qd'><b>\"Email.\"</b>: a single word gives no topic, recipient, or goal.</span><span class='qd'><b>\"Help me.\"</b>: this states no task at all, forcing the model to ask or assume.</span>" },
{ id:"D3-003", domain:3, obj:"3.1", diff:"hard", q:"A prompt that clearly states what you want the AI to DO is providing which component?", options:["The billing information","The model's training date","The task or instruction","The screen resolution"], answer:2, explain:"<strong>The task or instruction</strong> is the action verb of a prompt (summarize, draft, compare) that tells the model the job to perform.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The billing information</b>: payment details have nothing to do with instructing the model.</span><span class='qd'><b>The model's training date</b>: when the model was trained is metadata, not part of your instruction.</span><span class='qd'><b>The screen resolution</b>: display settings do not shape the request.</span>" },
{ id:"D3-004", domain:3, obj:"3.1", diff:"medium", q:"Why does specifying a desired length (for example, \"in about 100 words\") improve a prompt?", options:["It makes the AI run on a faster server","It guarantees the facts will be correct","It hides your request from the vendor","It sets a clear expectation so the answer is not too long or too short for your need"], answer:3, explain:"<strong>Setting a clear expectation</strong> for length steers the model toward output that fits how you plan to use it, reducing rework.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>It makes the AI run on a faster server</b>: length in the prompt does not change server hardware.</span><span class='qd'><b>It guarantees the facts will be correct</b>: length has no bearing on accuracy; you still must verify.</span><span class='qd'><b>It hides your request from the vendor</b>: specifying length does nothing for privacy.</span>" },
{ id:"D3-005", domain:3, obj:"3.1", diff:"easy", q:"You ask an assistant to \"make this shorter\" but paste nothing. What is the most likely result?", options:["The model cannot act well because there is no text to shorten, so it may ask for it or guess","The model shortens a random document from the internet","The model deletes files on your computer","The model shortens your subscription length"], answer:0, explain:"<strong>The model cannot act well without the text</strong>; a shortening task needs the source content, so a good assistant will request it rather than invent one.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The model shortens a random document from the internet</b>: it has no target and does not fetch arbitrary files to edit.</span><span class='qd'><b>The model deletes files on your computer</b>: a chat assistant does not delete local files.</span><span class='qd'><b>The model shortens your subscription length</b>: the word shorter refers to your text, not your account.</span>" },
{ id:"D3-006", domain:3, obj:"3.1", diff:"hard", q:"Which of these is the clearest example of stating the FORMAT you want?", options:["\"Answer nicely.\"","\"Give the answer as a bulleted list of five items.\"","\"Be smart about it.\"","\"Do your best.\""], answer:1, explain:"<strong>Asking for a bulleted list of five items</strong> names a concrete output structure the model can follow exactly.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>\"Answer nicely.\"</b>: nicely describes tone loosely, not a format.</span><span class='qd'><b>\"Be smart about it.\"</b>: this is an attitude, not a structure.</span><span class='qd'><b>\"Do your best.\"</b>: this adds nothing about how the output should be shaped.</span>" },
{ id:"D3-007", domain:3, obj:"3.1", diff:"medium", q:"A coworker's prompt keeps producing answers that are too technical for their audience. Which single addition would most directly fix this?", options:["Ask the AI to answer faster","Type the prompt in all capital letters","Tell the AI who the audience is, e.g., \"explain for a non-technical small-business owner\"","Add more exclamation points"], answer:2, explain:"<strong>Naming the audience</strong> lets the model calibrate vocabulary and depth to the reader, which is the direct cause of the mismatch.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Ask the AI to answer faster</b>: speed does not change reading level.</span><span class='qd'><b>Type the prompt in all capital letters</b>: capitalization does not adjust technicality.</span><span class='qd'><b>Add more exclamation points</b>: punctuation does not set the audience.</span>" },
{ id:"D3-008", domain:3, obj:"3.1", diff:"easy", q:"Including an example of the output you want (a sample) in your prompt mainly helps because it:", options:["Makes the model type more slowly","Removes the need to ever verify the answer","Connects the model to your email account","Shows the model the exact style and structure to imitate"], answer:3, explain:"<strong>A sample shows the model the target style and structure</strong>, so it can match tone, layout, and level without you describing every detail in words.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Makes the model type more slowly</b>: examples do not affect speed.</span><span class='qd'><b>Removes the need to ever verify the answer</b>: you still must check facts regardless of examples.</span><span class='qd'><b>Connects the model to your email account</b>: an example does not grant any access.</span>" },
{ id:"D3-009", domain:3, obj:"3.1", diff:"medium", q:"Which prompt best combines a task, a constraint, and a format in one request?", options:["\"Summarize this article in three bullet points, each under 15 words.\"","\"Summarize this.\"","\"Tell me about the article and other stuff.\"","\"Article summary maybe?\""], answer:0, explain:"<strong>The three-bullet request under 15 words each</strong> pairs the task (summarize), a constraint (word limit), and a format (bullets), giving precise direction.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>\"Summarize this.\"</b>: it has the task but no constraint or format.</span><span class='qd'><b>\"Tell me about the article and other stuff.\"</b>: other stuff is undefined and adds ambiguity.</span><span class='qd'><b>\"Article summary maybe?\"</b>: the tentative phrasing gives no length or structure.</span>" },
{ id:"D3-010", domain:3, obj:"3.1", diff:"hard", q:"What is the main risk of an extremely vague prompt like \"help with my project\"?", options:["The model will refuse to ever respond again","The model must guess your intent, so the answer is often off-target","The model charges extra money automatically","The model will email your project team"], answer:1, explain:"<strong>The model must guess your intent</strong> when the prompt lacks specifics, which commonly yields generic or mismatched output.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The model will refuse to ever respond again</b>: vagueness does not cause a permanent refusal.</span><span class='qd'><b>The model charges extra money automatically</b>: a vague prompt does not change billing.</span><span class='qd'><b>The model will email your project team</b>: it does not contact anyone on its own.</span>" },
{ id:"D3-011", domain:3, obj:"3.1", diff:"medium", q:"You want a first draft you can quickly edit, not a finished piece. How should the prompt reflect that?", options:["Insist the answer be perfect and final on the first try","Say nothing about drafts and hope for the best","Ask explicitly for a rough first draft and note you will refine it","Ask for the shortest possible answer regardless of usefulness"], answer:2, explain:"<strong>Asking explicitly for a rough first draft</strong> sets expectations so the model prioritizes coverage and speed over polish, matching your plan to edit.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Insist the answer be perfect and final on the first try</b>: demanding perfection wastes effort when you intend to revise anyway.</span><span class='qd'><b>Say nothing about drafts and hope for the best</b>: leaving intent unstated invites a mismatch.</span><span class='qd'><b>Ask for the shortest possible answer regardless of usefulness</b>: brevity for its own sake may strip needed content.</span>" },
{ id:"D3-012", domain:3, obj:"3.1", diff:"easy", q:"A user reports that a well-written prompt still returns a generic answer. Which explanation is most reasonable before blaming the model?", options:["The model is intentionally withholding a better answer to save energy","The prompt is fine, so the internet must be broken","The model only works well on Tuesdays","The prompt may still omit key context the model needs, such as the specific goal or audience"], answer:3, explain:"<strong>Missing key context</strong> such as the goal or audience is the most common cause of generic output even when phrasing is clean.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The model is intentionally withholding a better answer to save energy</b>: models do not strategically hide better answers from you.</span><span class='qd'><b>The prompt is fine, so the internet must be broken</b>: a generic answer is not an outage symptom.</span><span class='qd'><b>The model only works well on Tuesdays</b>: output quality is not tied to the day of the week.</span>" },
{ id:"D3-013", domain:3, obj:"3.1", diff:"medium", q:"Which addition turns \"write a product description\" into a much stronger prompt?", options:["\"...for a reusable stainless-steel water bottle, 60 words, upbeat tone, aimed at hikers.\"","\"...and make it good.\"","\"...quickly.\"","\"...please.\""], answer:0, explain:"<strong>Naming the product, length, tone, and audience</strong> supplies the concrete details the model needs to produce a fitting description.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>\"...and make it good.\"</b>: good is subjective and gives no direction.</span><span class='qd'><b>\"...quickly.\"</b>: speed says nothing about content.</span><span class='qd'><b>\"...please.\"</b>: politeness does not add specificity.</span>" },
{ id:"D3-014", domain:3, obj:"3.1", diff:"hard", q:"Setting the tone in a prompt (for example, \"professional\" or \"casual\") mainly controls:", options:["How fast the model responds","How formal or relaxed the wording of the response feels","Whether the answer is factually correct","How much the subscription costs"], answer:1, explain:"<strong>Tone controls how formal or relaxed the wording feels</strong>, aligning the voice to your context such as a work email versus a friendly note.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>How fast the model responds</b>: tone does not affect response speed.</span><span class='qd'><b>Whether the answer is factually correct</b>: tone is about style, not accuracy.</span><span class='qd'><b>How much the subscription costs</b>: tone has no effect on price.</span>" },
{ id:"D3-015", domain:3, obj:"3.1", diff:"easy", q:"You keep getting answers that assume the wrong country's rules. What prompt fix targets the root cause?", options:["Ask the model to try harder","Repeat the same prompt three times","State the location or jurisdiction explicitly, e.g., \"assume rules in Canada\"","Switch to a longer subscription"], answer:2, explain:"<strong>Stating the location explicitly</strong> removes the ambiguity that leads the model to default to the wrong region's assumptions.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Ask the model to try harder</b>: effort framing does not supply the missing location.</span><span class='qd'><b>Repeat the same prompt three times</b>: repetition without new information changes nothing.</span><span class='qd'><b>Switch to a longer subscription</b>: plan length is unrelated to jurisdiction.</span>" },
{ id:"D3-016", domain:3, obj:"3.1", diff:"medium", q:"Which is the best reason to break a big request into a clear list of sub-tasks in one prompt?", options:["It forces the model to answer in another language","It makes the answer impossible to edit later","It prevents you from ever asking follow-ups","It helps the model address each part instead of missing some"], answer:3, explain:"<strong>Listing sub-tasks helps the model address each part</strong>, reducing the chance that a portion of a multi-part request is skipped.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>It forces the model to answer in another language</b>: a task list does not change language.</span><span class='qd'><b>It makes the answer impossible to edit later</b>: structure does not lock the output.</span><span class='qd'><b>It prevents you from ever asking follow-ups</b>: you can always ask more.</span>" },
{ id:"D3-017", domain:3, obj:"3.1", diff:"medium", q:"A good prompt often answers which basic questions for the model?", options:["What to do, for whom, and in what form","What the weather is and what time it is","Which browser and mouse you use","What the model had for breakfast"], answer:0, explain:"<strong>What to do, for whom, and in what form</strong> are the core details that let the model target the task, audience, and output shape.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>What the weather is and what time it is</b>: these rarely matter to a writing or analysis task.</span><span class='qd'><b>Which browser and mouse you use</b>: device details do not shape the content.</span><span class='qd'><b>What the model had for breakfast</b>: models do not eat and this is irrelevant.</span>" },
{ id:"D3-018", domain:3, obj:"3.1", diff:"hard", q:"Which prompt shows the best use of a constraint to keep the answer practical?", options:["\"List tools.\"","\"List only free tools I can use in a web browser without installing anything.\"","\"List every tool that has ever existed.\"","\"List tools but surprise me.\""], answer:1, explain:"<strong>Constraining to free, browser-based, no-install tools</strong> narrows the output to options that fit real limits, making it directly usable.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>\"List tools.\"</b>: with no constraints the list may be huge and impractical.</span><span class='qd'><b>\"List every tool that has ever existed.\"</b>: an exhaustive impossible list is not useful.</span><span class='qd'><b>\"List tools but surprise me.\"</b>: surprise adds randomness, not usefulness.</span>" },
{ id:"D3-019", domain:3, obj:"3.1", diff:"easy", q:"You want the model to say when it is unsure rather than guess. Best prompt addition?", options:["\"Never admit any uncertainty.\"","\"Always sound completely certain.\"","\"If you are not confident about a fact, say so instead of guessing.\"","\"Answer only in one word.\""], answer:2, explain:"<strong>Asking it to flag low confidence</strong> encourages the model to signal uncertainty, which helps you decide what to verify.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>\"Never admit any uncertainty.\"</b>: this suppresses exactly the signal you want.</span><span class='qd'><b>\"Always sound completely certain.\"</b>: forced confidence hides real doubt and misleads you.</span><span class='qd'><b>\"Answer only in one word.\"</b>: a single word leaves no room to express uncertainty.</span>" },
{ id:"D3-020", domain:3, obj:"3.1", diff:"medium", q:"Which is the clearest way to set the goal of a prompt?", options:["\"Words about training.\"","\"Training stuff.\"","\"You know what I mean.\"","\"My goal is to convince my manager to approve a two-day training.\""], answer:3, explain:"<strong>Stating the persuasion goal and the manager audience</strong> lets the model aim the content at the outcome you want.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>\"Words about training.\"</b>: this names a topic but no goal.</span><span class='qd'><b>\"Training stuff.\"</b>: it is too vague to steer the output.</span><span class='qd'><b>\"You know what I mean.\"</b>: the model cannot read your mind; state it.</span>" },
{ id:"D3-021", domain:3, obj:"3.1", diff:"easy", q:"A prompt asks for \"a table\" but the result is a paragraph. What was probably missing or unclear?", options:["The format request was not explicit enough, e.g., columns and rows to include","The model does not know what a table is","The internet connection dropped","The keyboard was set to the wrong language"], answer:0, explain:"<strong>An under-specified format request</strong> is the usual cause; naming the exact columns and rows makes the table structure unambiguous.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The model does not know what a table is</b>: models handle tables routinely.</span><span class='qd'><b>The internet connection dropped</b>: a paragraph output is not a connectivity symptom.</span><span class='qd'><b>The keyboard was set to the wrong language</b>: keyboard language does not change output structure.</span>" },
{ id:"D3-022", domain:3, obj:"3.1", diff:"medium", q:"Which detail is LEAST useful to include in a typical writing prompt?", options:["The intended audience","The brand of computer you are typing on","The desired length","The tone you want"], answer:1, explain:"<strong>The brand of computer</strong> has no bearing on the words the model writes, unlike audience, length, and tone.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The intended audience</b>: audience strongly shapes vocabulary and depth.</span><span class='qd'><b>The desired length</b>: length keeps the output the right size.</span><span class='qd'><b>The tone you want</b>: tone sets the voice appropriately.</span>" },
{ id:"D3-023", domain:3, obj:"3.1", diff:"hard", q:"You want output you can paste straight into a spreadsheet. Which prompt component matters most?", options:["A friendly greeting","A request to answer quickly","A precise format spec, e.g., \"comma-separated values with headers: Name, Email, City\"","A note about your favorite color"], answer:2, explain:"<strong>A precise format spec such as CSV with named headers</strong> ensures the output drops cleanly into a spreadsheet without reformatting.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A friendly greeting</b>: pleasantries do not shape machine-readable output.</span><span class='qd'><b>A request to answer quickly</b>: speed does not affect the data format.</span><span class='qd'><b>A note about your favorite color</b>: irrelevant to the structure needed.</span>" },
{ id:"D3-024", domain:3, obj:"3.1", diff:"medium", q:"Which prompt best reduces the chance of an overly long, rambling answer?", options:["\"Say as much as you possibly can.\"","\"Explain everything you know about the topic.\"","\"Take your time and be thorough beyond limits.\"","\"Answer in no more than three sentences.\""], answer:3, explain:"<strong>Capping the answer at three sentences</strong> directly constrains length, preventing rambling.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>\"Say as much as you possibly can.\"</b>: this invites the exact bloat you want to avoid.</span><span class='qd'><b>\"Explain everything you know about the topic.\"</b>: an open-ended dump tends to ramble.</span><span class='qd'><b>\"Take your time and be thorough beyond limits.\"</b>: removing limits encourages length.</span>" },
{ id:"D3-025", domain:3, obj:"3.1", diff:"easy", q:"In prompt terms, what is a \"constraint\"?", options:["A limit or rule the answer must follow, like a word count or \"no jargon\"","The name of the AI company","A type of computer chip","A password for the tool"], answer:0, explain:"<strong>A constraint is a limit or rule the answer must follow</strong>, such as a word count, tone rule, or a ban on jargon.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The name of the AI company</b>: that is a vendor, not a rule for the answer.</span><span class='qd'><b>A type of computer chip</b>: hardware is unrelated to prompt rules.</span><span class='qd'><b>A password for the tool</b>: credentials are not answer constraints.</span>" },
{ id:"D3-026", domain:3, obj:"3.1", diff:"hard", q:"Which is the strongest single-sentence prompt for a busy reader?", options:["\"VPN?\"","\"In one paragraph, explain what a VPN does for a non-technical employee.\"","\"Tell me about networking in general.\"","\"Explain computers.\""], answer:1, explain:"<strong>The one-paragraph, audience-aware VPN explanation</strong> sets length, topic, and reader level in a single tight instruction.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>\"VPN?\"</b>: this gives no length or audience and invites a generic reply.</span><span class='qd'><b>\"Tell me about networking in general.\"</b>: far too broad for a busy reader.</span><span class='qd'><b>\"Explain computers.\"</b>: the scope is enormous and unfocused.</span>" },
{ id:"D3-027", domain:3, obj:"3.1", diff:"medium", q:"A prompt includes many details but the answer still misses the point. What is the best next diagnostic step?", options:["Assume the model is broken and stop using it","Add ten more unrelated details","Check whether the details are relevant and whether the main task is stated plainly up front","Delete all instructions and send a blank message"], answer:2, explain:"<strong>Checking relevance and whether the task is stated plainly</strong> catches the common problem of important instructions being buried under noise.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Assume the model is broken and stop using it</b>: giving up skips an easy fix.</span><span class='qd'><b>Add ten more unrelated details</b>: extra noise makes the miss worse.</span><span class='qd'><b>Delete all instructions and send a blank message</b>: a blank prompt provides nothing to act on.</span>" },
{ id:"D3-028", domain:3, obj:"3.1", diff:"easy", q:"Which phrase best specifies the reading level of an answer?", options:["\"Explain it well.\"","\"Explain it fast.\"","\"Explain it in blue.\"","\"Explain it so a 12-year-old could understand.\""], answer:3, explain:"<strong>Framing it for a 12-year-old</strong> gives the model a concrete reading level to match.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>\"Explain it well.\"</b>: well is subjective and sets no level.</span><span class='qd'><b>\"Explain it fast.\"</b>: speed is not a reading level.</span><span class='qd'><b>\"Explain it in blue.\"</b>: color is meaningless for text difficulty.</span>" },
{ id:"D3-029", domain:3, obj:"3.1", diff:"medium", q:"You want the model to focus only on the marketing angle, not the legal one. Best approach?", options:["State the scope: \"Focus only on marketing; do not cover legal issues.\"","Hope the model chooses correctly","Ask about everything and sort it out later","Type the word marketing once with no context"], answer:0, explain:"<strong>Stating the scope explicitly</strong> tells the model what to include and exclude, keeping the answer on the marketing angle.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Hope the model chooses correctly</b>: leaving scope to chance often fails.</span><span class='qd'><b>Ask about everything and sort it out later</b>: this creates extra work and noise.</span><span class='qd'><b>Type the word marketing once with no context</b>: a bare keyword does not define scope.</span>" },
{ id:"D3-030", domain:3, obj:"3.1", diff:"hard", q:"Overall, the biggest advantage of a specific prompt over a vague one is that it:", options:["Makes the model free to use","Reduces guessing so the answer better matches your real need","Guarantees zero factual errors","Removes the need to read the answer"], answer:1, explain:"<strong>Reducing guessing</strong> is the core benefit; specificity aligns the output with your actual intent.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Makes the model free to use</b>: specificity does not change pricing.</span><span class='qd'><b>Guarantees zero factual errors</b>: even specific prompts can yield mistakes to verify.</span><span class='qd'><b>Removes the need to read the answer</b>: you always review the output.</span>" },
{ id:"D3-031", domain:3, obj:"3.2", diff:"medium", q:"In a Role-Task-Context-Format prompt, what does the \"Role\" part do?", options:["Sets the price you pay","Chooses the font of the answer","Tells the AI what perspective or persona to adopt, e.g., \"act as a travel agent\"","Decides which country you live in"], answer:2, explain:"<strong>The Role tells the AI which perspective to adopt</strong>, which shapes the framing and vocabulary of the response.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Sets the price you pay</b>: a role has no effect on cost.</span><span class='qd'><b>Chooses the font of the answer</b>: fonts are display settings, not a role.</span><span class='qd'><b>Decides which country you live in</b>: your location is separate from the assigned persona.</span>" },
{ id:"D3-032", domain:3, obj:"3.2", diff:"easy", q:"Which prompt follows the Role-Task-Context-Format pattern most completely?", options:["\"Lunch ideas.\"","\"You are helpful. Thanks.\"","\"Give me a list.\"","\"Act as a nutrition coach. Suggest a weekday lunch plan. I am vegetarian and busy. Give it as a 5-item bulleted list.\""], answer:3, explain:"<strong>The nutrition-coach prompt</strong> names a Role, a Task, Context (vegetarian and busy), and a Format (5-item list), covering all four parts.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>\"Lunch ideas.\"</b>: it states only a rough task.</span><span class='qd'><b>\"You are helpful. Thanks.\"</b>: this sets no task, context, or format.</span><span class='qd'><b>\"Give me a list.\"</b>: it names a format but no role, task detail, or context.</span>" },
{ id:"D3-033", domain:3, obj:"3.2", diff:"medium", q:"Which is the clearest weak-to-strong upgrade of \"write a bio\"?", options:["\"Act as a copywriter. Write a 50-word professional LinkedIn bio for a new project manager who values teamwork. Use first person.\"","\"Write a bio, thanks.\"","\"Bio please, make it nice.\"","\"Write a bio about a person.\""], answer:0, explain:"<strong>The copywriter version</strong> adds role, length, platform, subject, value, and voice, transforming a vague ask into a strong prompt.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>\"Write a bio, thanks.\"</b>: politeness does not add specificity.</span><span class='qd'><b>\"Bio please, make it nice.\"</b>: nice is subjective and unhelpful.</span><span class='qd'><b>\"Write a bio about a person.\"</b>: a person is generic with no details.</span>" },
{ id:"D3-034", domain:3, obj:"3.2", diff:"hard", q:"The \"Context\" element of a strong prompt provides:", options:["The exact server the model runs on","Background facts about your situation that help the AI tailor the answer","The color scheme of the app","The AI vendor's stock price"], answer:1, explain:"<strong>Context provides background facts about your situation</strong>, letting the model tailor the response to your circumstances.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The exact server the model runs on</b>: infrastructure is irrelevant to tailoring content.</span><span class='qd'><b>The color scheme of the app</b>: appearance settings are not context for the task.</span><span class='qd'><b>The AI vendor's stock price</b>: finances of the vendor do not shape your answer.</span>" },
{ id:"D3-035", domain:3, obj:"3.2", diff:"easy", q:"Why can assigning a Role like \"act as an experienced teacher\" improve an explanation?", options:["It makes the model factually perfect","It speeds up the internet","It nudges the model toward a clear, patient, level-appropriate teaching style","It changes your account type"], answer:2, explain:"<strong>A teacher role nudges the model toward a clear, patient style</strong>, often improving structure and approachability.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>It makes the model factually perfect</b>: a role does not guarantee accuracy.</span><span class='qd'><b>It speeds up the internet</b>: personas do not affect connectivity.</span><span class='qd'><b>It changes your account type</b>: a role has no effect on your subscription.</span>" },
{ id:"D3-036", domain:3, obj:"3.2", diff:"medium", q:"A weak prompt is \"give me feedback on my resume.\" Which strong version best applies all four RTCF parts?", options:["\"Feedback on resume, be honest.\"","\"Resume help, act smart.\"","\"You are great. Fix my resume.\"","\"Act as a hiring manager in marketing. Review the pasted resume for a mid-level role. It targets brand jobs. Give 5 prioritized bullet suggestions.\""], answer:3, explain:"<strong>The hiring-manager version</strong> supplies Role (hiring manager), Task (review), Context (mid-level brand role), and Format (5 prioritized bullets).<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>\"Feedback on resume, be honest.\"</b>: it lacks role, context, and format.</span><span class='qd'><b>\"Resume help, act smart.\"</b>: act smart is not a defined role or format.</span><span class='qd'><b>\"You are great. Fix my resume.\"</b>: flattery adds nothing structural.</span>" },
{ id:"D3-037", domain:3, obj:"3.2", diff:"medium", q:"Which statement about the Format element is correct?", options:["It defines the shape of the output, such as a table, email, or numbered list","It determines whether the answer is legal advice","It selects the model's training data","It sets your device's battery level"], answer:0, explain:"<strong>Format defines the shape of the output</strong>, guiding whether you get a table, an email, or a numbered list.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>It determines whether the answer is legal advice</b>: format is about structure, not legal status.</span><span class='qd'><b>It selects the model's training data</b>: users do not pick training data through format.</span><span class='qd'><b>It sets your device's battery level</b>: hardware state is unrelated.</span>" },
{ id:"D3-038", domain:3, obj:"3.2", diff:"hard", q:"Which of these is primarily a Task statement?", options:["\"Act as a salesperson.\"","\"Compare two phone plans and recommend one.\"","\"I have a small budget.\"","\"Answer as a table.\""], answer:1, explain:"<strong>Compare two phone plans and recommend one</strong> is the action the model must perform, which is the Task.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>\"Act as a salesperson.\"</b>: that assigns a Role, not the task.</span><span class='qd'><b>\"I have a small budget.\"</b>: that is Context.</span><span class='qd'><b>\"Answer as a table.\"</b>: that is Format.</span>" },
{ id:"D3-039", domain:3, obj:"3.2", diff:"easy", q:"You give a strong RTCF prompt but the Role and Task conflict (e.g., \"act as a poet\" but \"write a tax form\"). What is the likely effect?", options:["The model refuses to run forever","The answer becomes automatically correct","Mixed or awkward output, because the persona does not fit the task","The app deletes your account"], answer:2, explain:"<strong>A mismatched persona and task yield mixed or awkward output</strong>, since a poet framing does not suit a tax form.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The model refuses to run forever</b>: a mismatch does not cause a permanent refusal.</span><span class='qd'><b>The answer becomes automatically correct</b>: conflict does not improve accuracy.</span><span class='qd'><b>The app deletes your account</b>: prompt conflicts have no such effect.</span>" },
{ id:"D3-040", domain:3, obj:"3.2", diff:"medium", q:"Which pairing correctly matches an RTCF element to an example?", options:["Role = \"summarize the report\"","Task = \"act as an accountant\"","Context = \"give it as bullet points\"","Format = \"as a three-column table\""], answer:3, explain:"<strong>Format = as a three-column table</strong> correctly labels an output structure.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Role = \"summarize the report\"</b>: summarizing is a Task, not a Role.</span><span class='qd'><b>Task = \"act as an accountant\"</b>: acting as someone is a Role.</span><span class='qd'><b>Context = \"give it as bullet points\"</b>: bullet points describe Format.</span>" },
{ id:"D3-041", domain:3, obj:"3.2", diff:"easy", q:"Adding \"I am new to this topic\" to a prompt is an example of providing:", options:["Context that helps the model set the right level","A Format request","A Role for the AI","A word-count constraint"], answer:0, explain:"<strong>Saying you are new is Context</strong> that tells the model to keep the explanation basic and jargon-free.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A Format request</b>: it does not specify a structure.</span><span class='qd'><b>A Role for the AI</b>: it describes you, not a persona for the model.</span><span class='qd'><b>A word-count constraint</b>: no length limit is given.</span>" },
{ id:"D3-042", domain:3, obj:"3.2", diff:"medium", q:"Which is the best example of a strong Role that fits a customer-support task?", options:["\"Act as a stand-up comedian.\"","\"Act as a calm, helpful support agent who explains steps clearly.\"","\"Act as a race-car driver.\"","\"Act as a medieval knight.\""], answer:1, explain:"<strong>A calm, helpful support agent</strong> is a Role that matches the tone and goals of customer support.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>\"Act as a stand-up comedian.\"</b>: humor may undercut a support interaction.</span><span class='qd'><b>\"Act as a race-car driver.\"</b>: this persona is irrelevant to support.</span><span class='qd'><b>\"Act as a medieval knight.\"</b>: archaic framing does not fit the task.</span>" },
{ id:"D3-043", domain:3, obj:"3.2", diff:"hard", q:"You want the SAME task done in three formats (email, tweet, and bullet list). Best single-prompt approach?", options:["Send the word format and hope for three versions","Ask for one format and complain if you get one","Keep one Role/Task/Context and list all three Formats explicitly in the request","Write only the Role and nothing else"], answer:2, explain:"<strong>Keeping one Role, Task, and Context while listing all three Formats</strong> reuses the shared setup and asks clearly for each output shape.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Send the word format and hope for three versions</b>: a bare word gives no instruction.</span><span class='qd'><b>Ask for one format and complain if you get one</b>: you get what you asked for; ask for three.</span><span class='qd'><b>Write only the Role and nothing else</b>: without a task there is nothing to format.</span>" },
{ id:"D3-044", domain:3, obj:"3.2", diff:"medium", q:"Which change most improves \"tell me about marketing emails\"?", options:["\"Tell me about marketing emails soon.\"","\"Marketing emails, be brief maybe.\"","\"Emails, marketing, please help.\"","\"Act as an email marketer. Explain three subject-line tips for a small bakery. Keep it to a short list.\""], answer:3, explain:"<strong>The email-marketer version</strong> adds Role, a specific Task, Context (small bakery), and Format (short list).<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>\"Tell me about marketing emails soon.\"</b>: soon is not a useful addition.</span><span class='qd'><b>\"Marketing emails, be brief maybe.\"</b>: maybe undercuts the constraint.</span><span class='qd'><b>\"Emails, marketing, please help.\"</b>: keywords alone give no structure.</span>" },
{ id:"D3-045", domain:3, obj:"3.2", diff:"easy", q:"Which is true about weak prompts versus strong prompts?", options:["Strong prompts give more usable results because they reduce ambiguity","Weak prompts always produce shorter answers","Strong prompts require paying more money","Weak prompts are always faster and better"], answer:0, explain:"<strong>Strong prompts reduce ambiguity</strong>, which is why they tend to produce more usable results.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Weak prompts always produce shorter answers</b>: length varies and is not tied to weakness.</span><span class='qd'><b>Strong prompts require paying more money</b>: quality of wording does not change price.</span><span class='qd'><b>Weak prompts are always faster and better</b>: they are typically less useful, not better.</span>" },
{ id:"D3-046", domain:3, obj:"3.2", diff:"hard", q:"A user's RTCF prompt works, but they want it reusable for many products. What is the best move?", options:["Rewrite the entire prompt from scratch every time","Turn it into a template with a placeholder like [PRODUCT NAME] to fill in each time","Remove the Role and Format to save space","Delete the Context so it applies to nothing"], answer:1, explain:"<strong>Turning it into a template with a placeholder</strong> preserves the proven structure and lets you swap in each product quickly.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Rewrite the entire prompt from scratch every time</b>: that wastes the work you already refined.</span><span class='qd'><b>Remove the Role and Format to save space</b>: dropping useful parts weakens the prompt.</span><span class='qd'><b>Delete the Context so it applies to nothing</b>: removing context makes results generic.</span>" },
{ id:"D3-047", domain:3, obj:"3.2", diff:"medium", q:"Which is the best Context to add for a prompt asking for travel suggestions?", options:["\"Act as a pilot.\"","\"Give a bulleted list.\"","\"I have a $500 budget, three days, and prefer the outdoors.\"","\"Suggest travel.\""], answer:2, explain:"<strong>Budget, time, and preference</strong> are Context details that let the model tailor realistic travel suggestions.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>\"Act as a pilot.\"</b>: that is a Role, not context.</span><span class='qd'><b>\"Give a bulleted list.\"</b>: that is Format.</span><span class='qd'><b>\"Suggest travel.\"</b>: that is the Task with no context.</span>" },
{ id:"D3-048", domain:3, obj:"3.2", diff:"easy", q:"\"Format the answer as a step-by-step numbered list\" is best described as:", options:["A Role instruction","A Context detail","A pricing choice","A Format instruction"], answer:3, explain:"<strong>A step-by-step numbered list is a Format instruction</strong> because it dictates the output structure.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A Role instruction</b>: it does not assign a persona.</span><span class='qd'><b>A Context detail</b>: it gives no background about your situation.</span><span class='qd'><b>A pricing choice</b>: it has nothing to do with cost.</span>" },
{ id:"D3-049", domain:3, obj:"3.2", diff:"medium", q:"Which prompt is strong yet still likely to fail its goal, and why?", options:["\"Act as a doctor and diagnose my exact illness from this vague symptom.\" — a persona cannot replace a real medical exam","\"Act as an editor. Fix grammar in this paragraph. Keep my meaning. Return the edited text.\" — clear and doable","\"Act as a chef. Suggest a pasta recipe using tomatoes and basil. List ingredients then steps.\" — clear and doable","\"Act as a tutor. Explain photosynthesis for a 10-year-old in 4 sentences.\" — clear and doable"], answer:0, explain:"<strong>The doctor-diagnosis prompt</strong> is well-structured but fails because assigning a persona cannot substitute for a real medical evaluation.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>\"Act as an editor. Fix grammar in this paragraph. Keep my meaning. Return the edited text.\" — clear and doable</b>: this is a reasonable, achievable task.</span><span class='qd'><b>\"Act as a chef. Suggest a pasta recipe using tomatoes and basil. List ingredients then steps.\" — clear and doable</b>: this is achievable and appropriate.</span><span class='qd'><b>\"Act as a tutor. Explain photosynthesis for a 10-year-old in 4 sentences.\" — clear and doable</b>: this is a well-scoped, safe task.</span>" },
{ id:"D3-050", domain:3, obj:"3.2", diff:"hard", q:"You need consistent output across a team. How does RTCF help most?", options:["It hides prompts from teammates","It gives everyone a shared structure, so prompts and results are more uniform","It makes the model refuse different requests","It automatically translates every answer"], answer:1, explain:"<strong>A shared RTCF structure</strong> standardizes how the team writes prompts, producing more uniform, comparable results.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>It hides prompts from teammates</b>: RTCF does not conceal anything.</span><span class='qd'><b>It makes the model refuse different requests</b>: it structures requests, it does not block them.</span><span class='qd'><b>It automatically translates every answer</b>: translation is a separate instruction.</span>" },
{ id:"D3-051", domain:3, obj:"3.3", diff:"medium", q:"What is a \"context file\" in the sense of everyday AI tools?", options:["A file that speeds up your internet","A backup of the AI's source code","A document you attach or paste so the AI can use its contents when answering","A receipt for your subscription"], answer:2, explain:"<strong>A context file is a document you attach or paste</strong> so the model can reference its contents while answering.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A file that speeds up your internet</b>: context files are content, not network tools.</span><span class='qd'><b>A backup of the AI's source code</b>: users do not attach model source code.</span><span class='qd'><b>A receipt for your subscription</b>: billing records are unrelated to context.</span>" },
{ id:"D3-052", domain:3, obj:"3.3", diff:"easy", q:"Which source is safest to attach as context for a work summary?", options:["A random person's private medical record you found","Someone else's copyrighted book you scanned illegally","A stranger's leaked password list","A document your organization owns and allows you to use"], answer:3, explain:"<strong>A document your organization owns and permits</strong> is the appropriate, safe source to use as context.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A random person's private medical record you found</b>: using private health data you have no right to is a serious violation.</span><span class='qd'><b>Someone else's copyrighted book you scanned illegally</b>: illegal copies should not be used.</span><span class='qd'><b>A stranger's leaked password list</b>: handling stolen credentials is unsafe and unethical.</span>" },
{ id:"D3-053", domain:3, obj:"3.3", diff:"medium", q:"Before pasting a company report into a public AI tool, what should you check first?", options:["Whether your organization's policy allows sharing that data with the tool","Whether the report is printed in color","How many pages the report has","What font the report uses"], answer:0, explain:"<strong>Checking whether policy allows sharing</strong> protects confidential data and keeps you compliant before it leaves your control.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Whether the report is printed in color</b>: appearance is irrelevant to data-sharing risk.</span><span class='qd'><b>How many pages the report has</b>: length does not address the policy question.</span><span class='qd'><b>What font the report uses</b>: formatting has no bearing on safety.</span>" },
{ id:"D3-054", domain:3, obj:"3.3", diff:"hard", q:"Why does giving the model a relevant source document often improve the answer?", options:["It makes the model type in bold automatically","It grounds the response in your actual information instead of general assumptions","It guarantees the answer is legally binding","It prevents the model from ever making mistakes"], answer:1, explain:"<strong>A relevant source grounds the response in your actual information</strong>, reducing generic guesses and improving fit.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>It makes the model type in bold automatically</b>: sources do not change formatting.</span><span class='qd'><b>It guarantees the answer is legally binding</b>: nothing makes an AI answer legally binding.</span><span class='qd'><b>It prevents the model from ever making mistakes</b>: grounding helps but does not eliminate errors.</span>" },
{ id:"D3-055", domain:3, obj:"3.3", diff:"easy", q:"A teammate wants to paste a customer list with names and emails into a public chatbot to draft messages. What is the best guidance?", options:["Paste it all; convenience outweighs privacy","Paste it but add a smiley face for safety","Avoid pasting personal data into public tools; remove or anonymize it, or use an approved private tool","Paste only if the file is small"], answer:2, explain:"<strong>Avoiding personal data in public tools</strong>, and anonymizing or using an approved private tool, protects customers and meets privacy obligations.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Paste it all; convenience outweighs privacy</b>: convenience does not justify exposing personal data.</span><span class='qd'><b>Paste it but add a smiley face for safety</b>: an emoji does nothing for data protection.</span><span class='qd'><b>Paste only if the file is small</b>: size does not reduce the privacy risk of personal data.</span>" },
{ id:"D3-056", domain:3, obj:"3.3", diff:"medium", q:"Which is a good reason to prefer an official document over a random web forum post as context?", options:["Forum posts are always written in a nicer font","Official documents are always shorter","Forum posts are guaranteed to be current","Official documents are usually more accurate and authoritative"], answer:3, explain:"<strong>Official documents are usually more accurate and authoritative</strong>, making them a more reliable basis for the answer.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Forum posts are always written in a nicer font</b>: font is irrelevant to reliability.</span><span class='qd'><b>Official documents are always shorter</b>: length varies and is not the point.</span><span class='qd'><b>Forum posts are guaranteed to be current</b>: forum posts can be outdated or wrong.</span>" },
{ id:"D3-057", domain:3, obj:"3.3", diff:"medium", q:"You attach a policy PDF and ask a question, but the answer ignores it. What is a reasonable first step?", options:["Confirm the file uploaded and reference it directly, e.g., \"Using the attached policy, answer...\"","Assume the PDF format is banned forever","Delete the question and start a lawsuit","Change your keyboard language"], answer:0, explain:"<strong>Confirming the upload and referencing it directly</strong> ensures the model actually uses the attached source.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Assume the PDF format is banned forever</b>: PDFs are commonly supported.</span><span class='qd'><b>Delete the question and start a lawsuit</b>: this is a wild overreaction to a simple fix.</span><span class='qd'><b>Change your keyboard language</b>: language settings do not affect attachment use.</span>" },
{ id:"D3-058", domain:3, obj:"3.3", diff:"hard", q:"Which practice best balances usefulness and safety when adding context from a sensitive file?", options:["Paste the entire file including every private detail","Include only the specific sections needed and redact personal identifiers","Retype the file from memory to avoid uploading","Share the file link publicly so anyone can help"], answer:1, explain:"<strong>Including only needed sections and redacting identifiers</strong> gives the model enough to help while limiting exposure of sensitive data.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Paste the entire file including every private detail</b>: oversharing raises unnecessary risk.</span><span class='qd'><b>Retype the file from memory to avoid uploading</b>: retyping still exposes the same content and adds errors.</span><span class='qd'><b>Share the file link publicly so anyone can help</b>: public sharing broadens exposure dangerously.</span>" },
{ id:"D3-059", domain:3, obj:"3.3", diff:"easy", q:"A source you plan to attach is three years old. What is the smart move?", options:["Assume old information is always correct","Ignore the date entirely","Note the date and verify whether the information is still current before relying on it","Delete the date so no one notices"], answer:2, explain:"<strong>Noting the date and verifying currency</strong> guards against relying on outdated facts.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Assume old information is always correct</b>: age can make details obsolete.</span><span class='qd'><b>Ignore the date entirely</b>: dismissing recency risks using stale data.</span><span class='qd'><b>Delete the date so no one notices</b>: hiding the date deceives readers and yourself.</span>" },
{ id:"D3-060", domain:3, obj:"3.3", diff:"medium", q:"Which is the clearest example of a relevant context source for drafting a project update?", options:["A recipe for chocolate cake","A weather report from last year","A movie review you liked","Your team's meeting notes and task tracker for that project"], answer:3, explain:"<strong>Meeting notes and the task tracker</strong> are directly relevant to a project update and will ground the draft.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A recipe for chocolate cake</b>: unrelated to the project.</span><span class='qd'><b>A weather report from last year</b>: irrelevant and outdated.</span><span class='qd'><b>A movie review you liked</b>: has nothing to do with the update.</span>" },
{ id:"D3-061", domain:3, obj:"3.3", diff:"easy", q:"You are unsure if a document contains confidential client data. What is the safest default before attaching it to any AI tool?", options:["Treat it as sensitive and verify permissions or anonymize before sharing","Assume it is fine and paste it immediately","Paste it into several tools to compare","Email it to yourself first, then paste it everywhere"], answer:0, explain:"<strong>Treating unknown documents as sensitive</strong> and verifying or anonymizing first is the safe default when confidentiality is uncertain.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Assume it is fine and paste it immediately</b>: assuming safety can leak confidential data.</span><span class='qd'><b>Paste it into several tools to compare</b>: multiplying tools multiplies exposure.</span><span class='qd'><b>Email it to yourself first, then paste it everywhere</b>: spreading it widely worsens the risk.</span>" },
{ id:"D3-062", domain:3, obj:"3.3", diff:"medium", q:"Which statement about attaching sources is most accurate?", options:["Attaching any file guarantees a correct answer","A relevant, trustworthy source improves grounding, but you still verify important claims","Sources make verification unnecessary","Only the largest file should ever be attached"], answer:1, explain:"<strong>A relevant, trustworthy source improves grounding</strong>, yet verifying important claims remains necessary.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Attaching any file guarantees a correct answer</b>: attachments do not guarantee correctness.</span><span class='qd'><b>Sources make verification unnecessary</b>: you still confirm key facts.</span><span class='qd'><b>Only the largest file should ever be attached</b>: relevance matters more than size.</span>" },
{ id:"D3-063", domain:3, obj:"3.3", diff:"hard", q:"Pasting an unrelated document as context is likely to:", options:["Automatically improve the answer","Speed up the response time","Distract the model and lower answer quality","Change your account settings"], answer:2, explain:"<strong>Unrelated context distracts the model</strong> and can pull the answer off track.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Automatically improve the answer</b>: irrelevant material does not help.</span><span class='qd'><b>Speed up the response time</b>: extra irrelevant text does not speed things up.</span><span class='qd'><b>Change your account settings</b>: pasting text does not alter your account.</span>" },
{ id:"D3-064", domain:3, obj:"3.3", diff:"medium", q:"A vendor's public chatbot says conversations may be used to improve the service. What is the best implication for context files?", options:["Upload everything since improvement helps everyone","Only upload if the file is a PDF","Upload but change the file name first","Avoid uploading confidential or personal data unless the tool is approved for it"], answer:3, explain:"<strong>Avoiding confidential or personal uploads unless the tool is approved</strong> is the right response when data may be retained or reused.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Upload everything since improvement helps everyone</b>: helping the service does not justify leaking private data.</span><span class='qd'><b>Only upload if the file is a PDF</b>: format does not address the retention concern.</span><span class='qd'><b>Upload but change the file name first</b>: renaming does not protect the contents.</span>" },
{ id:"D3-065", domain:3, obj:"3.3", diff:"easy", q:"Which is the best way to point the model at the part of a long attachment you care about?", options:["Tell it exactly, e.g., \"Focus on section 3, the refund policy.\"","Attach it and say nothing specific","Attach five more files for good measure","Ask it to read your mind"], answer:0, explain:"<strong>Naming the exact section</strong> directs the model to the relevant part and avoids it wandering through the whole file.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Attach it and say nothing specific</b>: without direction the model may focus on the wrong part.</span><span class='qd'><b>Attach five more files for good measure</b>: extra files add noise, not focus.</span><span class='qd'><b>Ask it to read your mind</b>: the model cannot infer unstated intent reliably.</span>" },
{ id:"D3-066", domain:3, obj:"3.4", diff:"hard", q:"What is a \"context window\" in simple terms?", options:["The physical window near your computer","The limited amount of text the model can consider at once in a conversation","The time of day the tool works best","The warranty period of your device"], answer:1, explain:"<strong>The context window is the limited amount of text the model can consider at once</strong>, covering your prompt and the recent conversation.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The physical window near your computer</b>: this is unrelated to AI.</span><span class='qd'><b>The time of day the tool works best</b>: there is no such time-based window.</span><span class='qd'><b>The warranty period of your device</b>: hardware warranties are irrelevant.</span>" },
{ id:"D3-067", domain:3, obj:"3.4", diff:"medium", q:"In a very long chat, the model seems to \"forget\" something you said early on. What is the most likely cause?", options:["The model is angry with you","Your internet is too fast","Earlier text may have fallen outside the context window the model can currently see","The model deleted your account history on purpose"], answer:2, explain:"<strong>Earlier text falling outside the context window</strong> is the common reason a model loses track of very early details in a long chat.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The model is angry with you</b>: models do not have emotions that cause forgetting.</span><span class='qd'><b>Your internet is too fast</b>: connection speed does not remove context.</span><span class='qd'><b>The model deleted your account history on purpose</b>: it does not intentionally erase history.</span>" },
{ id:"D3-068", domain:3, obj:"3.4", diff:"easy", q:"What is a practical fix when important earlier details seem to have dropped out of a long conversation?", options:["Type in a bigger font","Wait a day and try the same chat","Add more emojis to remind the model","Restate the key details concisely in your next message"], answer:3, explain:"<strong>Restating key details concisely</strong> brings the needed information back into the current context window.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Type in a bigger font</b>: font size does not restore lost context.</span><span class='qd'><b>Wait a day and try the same chat</b>: waiting does not recover dropped context.</span><span class='qd'><b>Add more emojis to remind the model</b>: emojis do not re-add information.</span>" },
{ id:"D3-069", domain:3, obj:"3.4", diff:"medium", q:"You paste an enormous amount of unnecessary text into a chat. Beyond privacy, what is a likely downside?", options:["Important instructions can get buried, making the model's focus worse","The model will run faster and cleaner","The answer becomes guaranteed correct","Your screen resolution will improve"], answer:0, explain:"<strong>Important instructions can get buried</strong> in a flood of unnecessary text, degrading the model's focus on what matters.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The model will run faster and cleaner</b>: more irrelevant text does not speed or clean up the answer.</span><span class='qd'><b>The answer becomes guaranteed correct</b>: volume does not guarantee accuracy.</span><span class='qd'><b>Your screen resolution will improve</b>: pasting text has no effect on display.</span>" },
{ id:"D3-070", domain:3, obj:"3.4", diff:"hard", q:"\"Oversharing\" context in a prompt mainly refers to:", options:["Sharing your prompt with too many friends","Including more information than needed, which can add noise or expose private data","Using too many fonts in a document","Talking too much in meetings"], answer:1, explain:"<strong>Oversharing means including more than needed</strong>, which can dilute focus and risk exposing private information.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Sharing your prompt with too many friends</b>: that is a different kind of sharing.</span><span class='qd'><b>Using too many fonts in a document</b>: formatting is unrelated to oversharing context.</span><span class='qd'><b>Talking too much in meetings</b>: this is unrelated to prompt content.</span>" },
{ id:"D3-071", domain:3, obj:"3.4", diff:"medium", q:"Which approach best manages context in a focused task?", options:["Paste your entire week of notes just in case","Add unrelated files to seem thorough","Include only what is relevant to the current question","Repeat the same paragraph several times"], answer:2, explain:"<strong>Including only what is relevant</strong> keeps the model focused and avoids noise.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Paste your entire week of notes just in case</b>: irrelevant bulk adds distraction.</span><span class='qd'><b>Add unrelated files to seem thorough</b>: unrelated files hurt, not help.</span><span class='qd'><b>Repeat the same paragraph several times</b>: repetition wastes space and adds no value.</span>" },
{ id:"D3-072", domain:3, obj:"3.4", diff:"easy", q:"A long research chat is getting muddled. What is a clean way to reset focus without losing your key facts?", options:["Keep adding to the muddled chat indefinitely","Delete the app and reinstall it","Switch to typing in another language","Start a fresh chat and paste a short summary of only the essential facts and goal"], answer:3, explain:"<strong>Starting fresh with a short summary of essentials</strong> clears accumulated clutter while carrying forward what matters.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Keep adding to the muddled chat indefinitely</b>: this compounds the confusion.</span><span class='qd'><b>Delete the app and reinstall it</b>: reinstalling does not fix conversation focus.</span><span class='qd'><b>Switch to typing in another language</b>: language change does not reset context.</span>" },
{ id:"D3-073", domain:3, obj:"3.4", diff:"medium", q:"Which is a privacy-smart habit when adding context?", options:["Remove names, account numbers, and other sensitive details you do not need to include","Always include every personal detail available","Attach your passwords for verification","Share your home address for context"], answer:0, explain:"<strong>Removing unneeded sensitive details</strong> minimizes exposure while still giving the model what it needs.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Always include every personal detail available</b>: that maximizes risk needlessly.</span><span class='qd'><b>Attach your passwords for verification</b>: never share passwords with an AI tool.</span><span class='qd'><b>Share your home address for context</b>: personal addresses are rarely needed and risky.</span>" },
{ id:"D3-074", domain:3, obj:"3.4", diff:"hard", q:"You need the model to keep a specific instruction in mind for a long task. What helps most?", options:["Assume it will remember forever no matter what","Restate the key instruction periodically so it stays within the active context","Only say it once at the very start and never again","Hide the instruction inside unrelated text"], answer:1, explain:"<strong>Restating the key instruction periodically</strong> keeps it inside the active context so the model continues to follow it.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Assume it will remember forever no matter what</b>: very long chats can lose early instructions.</span><span class='qd'><b>Only say it once at the very start and never again</b>: it may scroll out of the window later.</span><span class='qd'><b>Hide the instruction inside unrelated text</b>: burying it makes it easy to miss.</span>" },
{ id:"D3-075", domain:3, obj:"3.4", diff:"easy", q:"Which trade-off best describes adding lots of context?", options:["More context is always better with no downsides","Less context is always better with no downsides","More relevant context can help, but too much irrelevant context can crowd out what matters","Context has no effect on the answer at all"], answer:2, explain:"<strong>Relevant context helps while excess irrelevant context crowds out what matters</strong>, capturing the real trade-off.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>More context is always better with no downsides</b>: too much noise degrades focus.</span><span class='qd'><b>Less context is always better with no downsides</b>: too little context yields generic answers.</span><span class='qd'><b>Context has no effect on the answer at all</b>: context clearly shapes results.</span>" },
{ id:"D3-076", domain:3, obj:"3.4", diff:"medium", q:"A prompt mixes three unrelated tasks in one giant message. What is a likely result?", options:["The model always nails all parts perfectly","The model ignores you completely","The model charges you three subscriptions","The model may handle some parts poorly because focus is split"], answer:3, explain:"<strong>Splitting focus across unrelated tasks</strong> often means some parts are handled poorly; separating them helps.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The model always nails all parts perfectly</b>: crowded prompts commonly drop details.</span><span class='qd'><b>The model ignores you completely</b>: it usually attempts a response, just less well.</span><span class='qd'><b>The model charges you three subscriptions</b>: prompt structure does not change billing.</span>" },
{ id:"D3-077", domain:3, obj:"3.4", diff:"medium", q:"Which is the safest to leave OUT of a prompt unless truly necessary?", options:["Your Social Security number","The topic of the task","The desired length","The tone you want"], answer:0, explain:"<strong>A Social Security number</strong> is highly sensitive and should be omitted unless absolutely required and the tool is approved.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The topic of the task</b>: the topic is essential to the request.</span><span class='qd'><b>The desired length</b>: length helps shape the output usefully.</span><span class='qd'><b>The tone you want</b>: tone helps match the voice appropriately.</span>" },
{ id:"D3-078", domain:3, obj:"3.4", diff:"hard", q:"You must summarize a 40-page document but only 10 pages are relevant. Best context strategy?", options:["Paste all 40 pages and hope the model figures it out","Provide just the relevant 10 pages and state which topic to summarize","Paste the document twice for emphasis","Provide none of it and ask the model to guess"], answer:1, explain:"<strong>Providing just the relevant 10 pages with a clear topic</strong> keeps the model focused and improves the summary.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Paste all 40 pages and hope the model figures it out</b>: the 30 irrelevant pages add noise.</span><span class='qd'><b>Paste the document twice for emphasis</b>: duplication wastes context space.</span><span class='qd'><b>Provide none of it and ask the model to guess</b>: without the source the summary is unfounded.</span>" },
{ id:"D3-079", domain:3, obj:"3.4", diff:"easy", q:"Which sign suggests you have added too much context?", options:["The model answers your exact question cleanly","The model asks a helpful clarifying question","The model starts mixing up details or answering the wrong part","The model produces a well-structured result"], answer:2, explain:"<strong>Mixing up details or answering the wrong part</strong> is a classic symptom that too much or conflicting context has crowded the request.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The model answers your exact question cleanly</b>: that indicates good, focused context.</span><span class='qd'><b>The model asks a helpful clarifying question</b>: that is a healthy sign, not overload.</span><span class='qd'><b>The model produces a well-structured result</b>: structure suggests the context worked.</span>" },
{ id:"D3-080", domain:3, obj:"3.4", diff:"medium", q:"Managing context well mostly means:", options:["Giving as little information as possible always","Giving as much information as possible always","Never giving any information","Giving the right information, in the right amount, for the current task"], answer:3, explain:"<strong>Giving the right information in the right amount</strong> for the task is the essence of good context management.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Giving as little information as possible always</b>: too little starves the model of needed detail.</span><span class='qd'><b>Giving as much information as possible always</b>: too much adds noise and risk.</span><span class='qd'><b>Never giving any information</b>: with nothing to work from, results are generic.</span>" },
{ id:"D3-081", domain:3, obj:"3.5", diff:"easy", q:"What is a \"multi-turn\" conversation with an AI tool?", options:["A back-and-forth exchange where each message can build on the previous ones","A single question with a single answer only","A conversation limited to one word each","A chat that must be finished in under a minute"], answer:0, explain:"<strong>A multi-turn conversation is a back-and-forth</strong> in which each message can build on what came before.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A single question with a single answer only</b>: that is a one-turn exchange.</span><span class='qd'><b>A conversation limited to one word each</b>: turns are not limited to single words.</span><span class='qd'><b>A chat that must be finished in under a minute</b>: there is no such time limit.</span>" },
{ id:"D3-082", domain:3, obj:"3.5", diff:"medium", q:"The model gives a good draft but it is too formal. What is the best follow-up?", options:["Start a brand-new unrelated chat","\"Make it more casual and friendly, keeping the same points.\"","Ask the model why it exists","Retype your entire original prompt from scratch"], answer:1, explain:"<strong>Asking it to make the draft more casual while keeping the points</strong> refines the existing output efficiently.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Start a brand-new unrelated chat</b>: you would lose the draft you want to adjust.</span><span class='qd'><b>Ask the model why it exists</b>: that does not move the task forward.</span><span class='qd'><b>Retype your entire original prompt from scratch</b>: unnecessary when a small follow-up will do.</span>" },
{ id:"D3-083", domain:3, obj:"3.5", diff:"hard", q:"Why is iterative refinement (asking follow-ups) often better than trying to write one perfect prompt?", options:["It always uses fewer total words","It removes the need to read any output","You can steer the output step by step based on what the model actually returns","It guarantees the first answer is final"], answer:2, explain:"<strong>You can steer the output step by step</strong> based on real results, which is the main advantage of iterating.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>It always uses fewer total words</b>: iteration may use more messages, not fewer.</span><span class='qd'><b>It removes the need to read any output</b>: you must read each result to refine.</span><span class='qd'><b>It guarantees the first answer is final</b>: iteration implies the first answer is not final.</span>" },
{ id:"D3-084", domain:3, obj:"3.5", diff:"medium", q:"Which follow-up best narrows an answer that was too broad?", options:["\"Tell me more about everything.\"","\"Add unrelated topics too.\"","\"Make it longer without focusing.\"","\"Focus only on the budgeting section and give three concrete tips.\""], answer:3, explain:"<strong>Focusing on the budgeting section with three concrete tips</strong> narrows scope and adds specificity.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>\"Tell me more about everything.\"</b>: this widens rather than narrows.</span><span class='qd'><b>\"Add unrelated topics too.\"</b>: adding topics broadens the answer.</span><span class='qd'><b>\"Make it longer without focusing.\"</b>: length without focus does not narrow anything.</span>" },
{ id:"D3-085", domain:3, obj:"3.5", diff:"easy", q:"After several refinements, the answer drifted away from your original goal. What is the best recovery move?", options:["Remind the model of the original goal and ask it to realign the latest version to it","Accept the drifted answer because you already spent effort","Delete the chat and never use AI again","Ask an unrelated question to reset"], answer:0, explain:"<strong>Reminding the model of the original goal and asking it to realign</strong> pulls the drifting output back on target.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Accept the drifted answer because you already spent effort</b>: sunk effort is not a reason to keep a wrong result.</span><span class='qd'><b>Delete the chat and never use AI again</b>: an overreaction to a fixable drift.</span><span class='qd'><b>Ask an unrelated question to reset</b>: that adds distraction, not realignment.</span>" },
{ id:"D3-086", domain:3, obj:"3.5", diff:"hard", q:"Which is a good habit when a follow-up request is complex?", options:["Assume the model remembers your exact intent perfectly","State clearly what to keep, what to change, and what to remove","Give only a one-word command","Change several unrelated things at once without saying so"], answer:1, explain:"<strong>Stating what to keep, change, and remove</strong> gives the model precise direction for a complex revision.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Assume the model remembers your exact intent perfectly</b>: it is safer to be explicit.</span><span class='qd'><b>Give only a one-word command</b>: one word is too vague for a complex change.</span><span class='qd'><b>Change several unrelated things at once without saying so</b>: unstated changes cause confusion.</span>" },
{ id:"D3-087", domain:3, obj:"3.5", diff:"medium", q:"The model misunderstood your request. What is the most effective response?", options:["Repeat the exact same words louder in capitals","Give up and accept the wrong answer","Clarify the specific misunderstanding and restate the intended outcome","Ask a completely different question instead"], answer:2, explain:"<strong>Clarifying the specific misunderstanding and restating the outcome</strong> targets the exact gap and guides a correct redo.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Repeat the exact same words louder in capitals</b>: identical wording is likely to repeat the misunderstanding.</span><span class='qd'><b>Give up and accept the wrong answer</b>: that abandons an easy fix.</span><span class='qd'><b>Ask a completely different question instead</b>: that leaves your original need unmet.</span>" },
{ id:"D3-088", domain:3, obj:"3.5", diff:"easy", q:"You want to compare three refined versions the model produced. Best follow-up?", options:["\"Just pick one for me without explaining.\"","\"Forget the earlier versions.\"","\"Make a fourth version instead.\"","\"Show all three versions side by side and note the key differences.\""], answer:3, explain:"<strong>Asking to show all three side by side with differences</strong> lets you evaluate and choose deliberately.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>\"Just pick one for me without explaining.\"</b>: this hides the reasoning you need to compare.</span><span class='qd'><b>\"Forget the earlier versions.\"</b>: discarding them defeats the comparison.</span><span class='qd'><b>\"Make a fourth version instead.\"</b>: that avoids comparing the three you have.</span>" },
{ id:"D3-089", domain:3, obj:"3.5", diff:"medium", q:"Which follow-up best turns a general answer into an actionable one?", options:["\"Turn this into a checklist I can follow this week.\"","\"Say it again in different words.\"","\"Add more theory and background.\"","\"Make it vaguer.\""], answer:0, explain:"<strong>Turning the answer into a weekly checklist</strong> converts general advice into concrete, actionable steps.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>\"Say it again in different words.\"</b>: rephrasing does not add action steps.</span><span class='qd'><b>\"Add more theory and background.\"</b>: extra theory is less actionable.</span><span class='qd'><b>\"Make it vaguer.\"</b>: vagueness reduces actionability.</span>" },
{ id:"D3-090", domain:3, obj:"3.5", diff:"hard", q:"A key benefit of continuing in the same chat rather than starting over is:", options:["The answer becomes legally certified","The model can build on the context already established in the conversation","The tool becomes free to use","The model forgets everything, which is helpful"], answer:1, explain:"<strong>The model can build on established context</strong> when you continue the same chat, saving you from re-explaining.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The answer becomes legally certified</b>: chats are not legal certifications.</span><span class='qd'><b>The tool becomes free to use</b>: continuing a chat does not change pricing.</span><span class='qd'><b>The model forgets everything, which is helpful</b>: forgetting would remove the benefit of continuity.</span>" },
{ id:"D3-091", domain:3, obj:"3.6", diff:"medium", q:"Why can a single chat that jumps between many unrelated topics become less helpful over time?", options:["It always makes answers shorter","It automatically improves every answer","Mixed topics can dilute focus and let earlier context crowd or confuse the current task","It changes the model into a different product"], answer:2, explain:"<strong>Mixed topics dilute focus</strong> and can let stale context confuse the current task, lowering quality.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>It always makes answers shorter</b>: topic mixing does not reliably shorten answers.</span><span class='qd'><b>It automatically improves every answer</b>: clutter tends to hurt, not help.</span><span class='qd'><b>It changes the model into a different product</b>: the model does not change identity.</span>" },
{ id:"D3-092", domain:3, obj:"3.6", diff:"easy", q:"You are done with one project and switching to a completely different one. What best maintains focus?", options:["Keep everything in one endless chat forever","Paste the old project's files into the new topic","Alternate between the two topics every message","Start a new chat for the new project so old context does not interfere"], answer:3, explain:"<strong>Starting a new chat for the new project</strong> keeps unrelated old context from interfering with the new work.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Keep everything in one endless chat forever</b>: mixing projects invites confusion.</span><span class='qd'><b>Paste the old project's files into the new topic</b>: that imports irrelevant context.</span><span class='qd'><b>Alternate between the two topics every message</b>: switching back and forth splits focus.</span>" },
{ id:"D3-093", domain:3, obj:"3.6", diff:"medium", q:"Midway through a focused task, you have a quick unrelated question. What keeps the main task on track?", options:["Ask the unrelated question in a separate chat, then return to the focused one","Interrupt the main task and mix the two together","Abandon the main task entirely","Ask both questions in the same sentence and hope"], answer:0, explain:"<strong>Using a separate chat for the unrelated question</strong> protects the main task's context and focus.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Interrupt the main task and mix the two together</b>: mixing clutters the main thread.</span><span class='qd'><b>Abandon the main task entirely</b>: that sacrifices your progress.</span><span class='qd'><b>Ask both questions in the same sentence and hope</b>: combining unrelated asks reduces quality.</span>" },
{ id:"D3-094", domain:3, obj:"3.6", diff:"hard", q:"A long working session has drifted and now contains contradictory instructions you gave at different times. Best fix to regain focus?", options:["Let the model choose which contradictory instruction to obey","Summarize the current, correct instructions in one message and ask the model to follow only those","Add even more instructions on top","Keep going and hope it sorts itself out"], answer:1, explain:"<strong>Summarizing the current correct instructions and asking it to follow only those</strong> resolves contradictions and restores focus.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Let the model choose which contradictory instruction to obey</b>: leaving it to chance is unreliable.</span><span class='qd'><b>Add even more instructions on top</b>: piling on worsens the contradictions.</span><span class='qd'><b>Keep going and hope it sorts itself out</b>: the conflict will likely persist.</span>" },
{ id:"D3-095", domain:3, obj:"3.6", diff:"easy", q:"Which habit best supports staying on topic in a session?", options:["Never mention the goal after the first message","Change the goal quietly every few messages","Periodically restate the goal so both you and the model stay aligned","Avoid ever summarizing progress"], answer:2, explain:"<strong>Periodically restating the goal</strong> keeps you and the model aligned as a session grows.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Never mention the goal after the first message</b>: the goal can drift out of view in long chats.</span><span class='qd'><b>Change the goal quietly every few messages</b>: silent changes cause misalignment.</span><span class='qd'><b>Avoid ever summarizing progress</b>: skipping summaries makes drift harder to catch.</span>" },
{ id:"D3-096", domain:3, obj:"3.6", diff:"medium", q:"You notice the model is now answering as if an earlier, abandoned plan is still active. What is the cleanest response?", options:["Assume it will figure out the switch on its own","Keep both plans alive and see what happens","Start typing faster to signal the change","Tell it that plan is dropped and restate the plan you are actually using now"], answer:3, explain:"<strong>Explicitly dropping the old plan and restating the current one</strong> removes the stale context guiding its answers.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Assume it will figure out the switch on its own</b>: it may keep following the old plan.</span><span class='qd'><b>Keep both plans alive and see what happens</b>: competing plans cause conflicting output.</span><span class='qd'><b>Start typing faster to signal the change</b>: typing speed communicates nothing to the model.</span>" },
{ id:"D3-097", domain:3, obj:"3.6", diff:"medium", q:"For a large multi-step deliverable, which practice best keeps a session focused end to end?", options:["Work in clear stages, confirm each stage, and summarize progress before moving on","Try to do all steps in one massive message with no checkpoints","Switch topics between every step to stay fresh","Never confirm anything until the very end"], answer:0, explain:"<strong>Working in clear stages with confirmations and summaries</strong> keeps the session organized and focused across many steps.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Try to do all steps in one massive message with no checkpoints</b>: a single giant message loses structure and details.</span><span class='qd'><b>Switch topics between every step to stay fresh</b>: constant switching breaks focus.</span><span class='qd'><b>Never confirm anything until the very end</b>: skipping checkpoints lets errors compound.</span>" },
{ id:"D3-098", domain:3, obj:"3.6", diff:"hard", q:"Which is a reason to occasionally summarize the conversation back to the model?", options:["It makes the model type in italics","It refreshes the key points in the active context and confirms shared understanding","It doubles your subscription length","It permanently locks the chat"], answer:1, explain:"<strong>Summarizing refreshes key points in the active context</strong> and confirms that you and the model share the same understanding.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>It makes the model type in italics</b>: summaries do not change formatting.</span><span class='qd'><b>It doubles your subscription length</b>: summarizing has no effect on your plan.</span><span class='qd'><b>It permanently locks the chat</b>: summaries do not lock anything.</span>" },
{ id:"D3-099", domain:3, obj:"3.6", diff:"easy", q:"Keeping one chat dedicated to one topic mainly helps by:", options:["Making the answers automatically correct","Removing the need to write clear prompts","Preserving relevant context and avoiding confusion from unrelated material","Guaranteeing the fastest possible responses"], answer:2, explain:"<strong>Dedicating a chat to one topic preserves relevant context</strong> and avoids confusion from unrelated material.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Making the answers automatically correct</b>: focus helps but does not guarantee correctness.</span><span class='qd'><b>Removing the need to write clear prompts</b>: clear prompts are still essential.</span><span class='qd'><b>Guaranteeing the fastest possible responses</b>: topic focus does not set response speed.</span>" },
{ id:"D3-100", domain:3, obj:"3.6", diff:"medium", q:"You are near the end of a very long, productive session and want to preserve the outcome for later. What is the most useful final step?", options:["Close the chat immediately without saving anything","Delete the session to keep things tidy","Ask an unrelated question to end on a fresh note","Ask the model to produce a concise summary of decisions and next steps you can save"], answer:3, explain:"<strong>Asking for a concise summary of decisions and next steps</strong> captures the outcome in a form you can save and reuse.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Close the chat immediately without saving anything</b>: you would lose the useful conclusions.</span><span class='qd'><b>Delete the session to keep things tidy</b>: deleting discards the work you want to keep.</span><span class='qd'><b>Ask an unrelated question to end on a fresh note</b>: that adds nothing to preserving the outcome.</span>" }
);
